import { createContext, useContext, useState } from 'react';
import API from '../api/axios'; // Siguraduhing tama ang path sa axios instance mo

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);

  // Gawin nating async para ito na ang tatawag sa Backend
  const login = async (email, password) => {
    try {
      const response = await API.post('/auth/login', { email, password });
      
      // I-extract ang user at token base sa response ng backend mo
      const userData = response.data.user; 
      const token = response.data.token;

      // I-save sa LocalStorage
      localStorage.setItem('user', JSON.stringify(userData));
      localStorage.setItem('token', token);

      // I-update ang global state para mag-render ulit ang Navbar
      setUser(userData);

      return userData; // Ibabalik ito sa LoginPage para sa redirection logic
    } catch (error) {
      throw error; // Ipasa ang error sa LoginPage para ma-display ang error message
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    window.location.href = '/login'; // Opsyonal: Force redirect sa login
  };

  return (
    <AuthContext.Provider value={{ user, setUser, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
